mapper.select:
SELECT *
FROM P_CPU_MEM_T
WHERE DEVICE_ID = #{deviceId}
  AND CORE_INDEX IS NULL
  AND COLLECTED_AT BETWEEN #{startTime} AND #{endTime}
ORDER BY COLLECTED_AT ASC

SELECT * FROM P_CPU_MEM_T WHERE DEVICE_ID IN
#{id}
AND CORE_INDEX IS NULL AND COLLECTED_AT BETWEEN #{startDate} AND #{endDate} ORDER BY DEVICE_ID, COLLECTED_AT ASC

SELECT DEVICE_ID, FROM_UNIXTIME(FLOOR(UNIX_TIMESTAMP(COLLECTED_AT)/#{intervalSec})*#{intervalSec}) AS COLLECTED_AT, ROUND(AVG(CPU_USAGE), 2) AS CPU_USAGE, ROUND(AVG(CPU_IDLE), 0) AS CPU_IDLE, ROUND(AVG(CPU_USER), 0) AS CPU_USER, ROUND(AVG(CPU_SYSTEM), 0) AS CPU_SYSTEM, MAX(MEM_TOTAL) AS MEM_TOTAL, ROUND(AVG(MEM_FREE), 0) AS MEM_FREE, ROUND(AVG(MEM_AVAIL), 0) AS MEM_AVAIL, ROUND(AVG(MEM_BUFFER), 0) AS MEM_BUFFER, ROUND(AVG(MEM_CACHE), 0) AS MEM_CACHE, ROUND(AVG(MEM_USED), 0) AS MEM_USED, ROUND(AVG(MEM_USAGE), 2) AS MEM_USAGE FROM P_CPU_MEM_T WHERE DEVICE_ID IN
#{id}
AND CORE_INDEX IS NULL AND COLLECTED_AT BETWEEN #{startDate} AND #{endDate} GROUP BY DEVICE_ID, FLOOR(UNIX_TIMESTAMP(COLLECTED_AT)/#{intervalSec}) ORDER BY DEVICE_ID, COLLECTED_AT ASC
